@ARTICLE{10.1152/ajpendo.00213.2025,
	author = {Shimada BK and Ogawa-Wong AN and Soares AG and Hallam KA and Santiago PJD and Saelua K and Nakahara-Akita KK and Torres DJ and Brockman JD and Kurokawa S and Ewell KL and Bellinger MT and Toh P and Lagatta Pamplona Remedios G and Alfulaij N and Swanson SM and Seyedali A and Zavacki AM and Berry MJ and Seale LA},
	title = {Global loss of selenocysteine lyase in mice drives lipid accumulation in brown adipocytes.},
	journal = {Am J Physiol Endocrinol Metab},
	year = {2026},
	abstract = {The enzyme selenocysteine (Sec) lyase (SCLY) decomposes Sec, releasing selenide for the synthesis of selenoproteins, which contain Sec in their primary structure and participate in strong redox reactions, maintaining redox balance. We previously showed that global disruption of the Scly gene (Scly KO) in mice leads to obesity. Targeted deletion of Scly in agouti-related peptide neurons enhances energy expenditure and brown adipose tissue (BAT) activation, augmenting leanness. We hypothesized that Scly KO mice develop obesity due to failure of BAT-controlled mechanisms of energy expenditure due to redirection of Sec to an alternative pathway. We analyzed BAT from male Scly KO mice on selenium (Se)-adequate [0.25 parts per million (ppm)] and Se-deficient (0.08 ppm) diets for morphology, Se content, selenoprotein expression, thyroid hormones, and additional Sec-using pathways. We found that the BAT of Scly KO mice was enlarged, with lower Se levels, and substantial whitening on a Se-adequate diet. This phenotype worsened on low Se and coincided with a mild impairment in adapting to cold exposure. BAT whitening coincided with an increase in triglycerides and reduced 3-hydroxy-3-methylglutaryl coenzyme A and cholesterol. BAT selenoproteins regulating energy metabolism, type 2 iodothyronine deiodinase (DIO2), glutathione peroxidase 1 (GPX1), and glutathione peroxidase 1 (GPX4), were significantly decreased. DIO2 reduction corresponded with an increase in thyroxine and thyroid-stimulating hormone and a reduction in heat-producing uncoupling protein 1. Downregulation of GPX4 did not affect ferroptosis in the BAT. Therefore, the whitened BAT of the Scly KO mouse is a multifactorial process involving the disruption of BAT function through changes to selenoproteins involved in energy metabolism.NEW & NOTEWORTHY Global loss of the selenocysteine-decomposing enzyme selenocysteine lyase in mice leads to lipid accumulation and whitening of the brown adipose tissue, with consequent obesity development. Selenocysteine lyase modulates selenium levels and selenoprotein expression, specifically GPX1, GPX4, and DIO2, in brown adipocytes. Selenocysteine metabolic fate hinges on the actions of selenocysteine lyase.},
	doi = {10.1152/ajpendo.00213.2025},
	pmid = {41452587 [Indexed for MEDLINE]},
	note = {PMC12857770}
}

@ARTICLE{10.1021/acs.jafc.5c12282,
	author = {Sang T and Xu T and Chen C and Wu J and Zhou C and Li F and Xu L and Liu S and Wang M and Zhang Y and Xia D and Chu L},
	title = {Ganoderma lucidum Polysaccharides Alleviate High-Fat Diet-Induced Obesity by Promoting Lipolysis and Inhibiting Inflammation through Lactobacillus johnsonii-Butyrate Axis.},
	journal = {J Agric Food Chem},
	year = {2026},
	abstract = {Ganoderma lucidum polysaccharides (GLPs) exert antiobesity effects that are linked to gut-microbiota modulation, yet the underlying mechanisms remain elusive. Here, we show that GLPs raise the fecal butyrate level, which in turn inhibits high-fat diet (HFD)-induced weight gain, fat accumulation, adipocyte hypertrophy, and elevated serum triglyceride by promoting adipose triglyceride lipase (ATGL) expression to activate lipolysis. GLPs and butyrate also strengthen the intestinal barrier, reflected by elevated tight junction proteins and goblet cells, leading to reduced serum lipopolysaccharide-binding protein (LBP) and attenuated white-adipose-tissue (WAT) inflammation. The intestinal barrier enhancement involves FABP4-PPARγ signaling. In addition, the butyrate-enhancement and antiobesity effects of GLPs are abolished after antibiotic-mediated microbiota depletion. Notably, GLPs selectively enrich the abundance of Lactobacillus, especially Lactobacillus johnsonii, whose supplementation alone increases fecal butyrate and recapitulates GLPs-induced benefits by reinforcing gut barrier integrity and lipolysis. Collectively, our findings identify the L. johnsonii-butyrate axis as a central target through which GLPs attenuate obesity and associated inflammation.},
	doi = {10.1021/acs.jafc.5c12282},
	pmid = {41442582 [Indexed for MEDLINE]}
}

@ARTICLE{10.1161/ATVBAHA.125.323273,
	author = {Yeh YS and Huang J and Liu Z and Cosme C Jr and Zhang X and Razani B},
	title = {Cytosolic Versus Lysosomal Lipolysis in Adipose Tissue: Opposing Roles in Cardiometabolic Disease.},
	journal = {Arterioscler Thromb Vasc Biol},
	year = {2026},
	abstract = {Adipose tissue lipid metabolism is a critical regulator of systemic energy balance, but its impact on cardiometabolic health is paradoxical. This review dissects the 2 primary lipolytic systems in adipocytes: the canonical cytosolic pathway driven by ATGL/PNPLA2 (adipose triglyceride lipase) and the lysosomal pathway governed by LAL/LIPA (lysosomal acid lipase). We present emerging evidence that these pathways exert opposing effects in the context of obesity. While excessive fatty acid efflux from dysregulated cytosolic lipolysis is a known driver of adiposopathic dyslipidemia, adipose inflammation, and direct cardiac lipotoxicity, which collectively impair cardiometabolic health, the activity of the lysosomal pathway is emerging as a protective counterbalance. Genetic and pharmacological studies demonstrate that inhibiting cytosolic ATGL is beneficial for metabolic health, whereas enhancing LAL-mediated lipolysis mitigates obesity-related dysfunction. This functional antagonism between cytosolic and lysosomal lipolysis presents a new paradigm in lipid metabolism, suggesting that therapeutic strategies must be pathway-specific. We conclude that selectively inhibiting pathogenic cytosolic lipid release while promoting beneficial lysosomal lipid processing offers a nuanced approach to treating metabolic disease.},
	doi = {10.1161/ATVBAHA.125.323273},
	pmid = {41431923 [Indexed for MEDLINE]},
	note = {PMC12758639}
}

@ARTICLE{10.1139/apnm-2025-0344,
	author = {Sakar M, Doğan Ç, Apaydın N, İpekoğlu G},
	title = {Does the MC4R rs17782313 gene polymorphism affect the rate of exercise-induced fat oxidation?},
	journal = {Appl Physiol Nutr Metab},
	year = {2026},
	abstract = {This study investigated the effect of the MC4R rs17782313 (T > C) polymorphism on substrate oxidation and metabolic responses during exercise in healthy sedentary men. Forty-eight participants (aged 20-30 years) underwent genotyping and completed a graded exercise test with respiratory gas analysis to assess oxygen consumption (VO2), respiratory quotient (RQ), and fat and carbohydrate oxidation rates. Participants were grouped as C-allele carriers (risk allele) and TT homozygotes. Group comparisons were conducted for VO2, RQ, substrate oxidation rates, and body mass index (BMI). Statistical analysis revealed no significant differences between genotypes in RQ, fat oxidation percentage, or carbohydrate oxidation percentage during moderate-intensity exercise (p > 0.05). However, significant differences were observed in BMI, with C-allele carriers exhibiting higher BMI values compared to TT homozygotes (p < 0.05). These results indicate that while the MC4R rs17782313 variant is associated with increased adiposity, it does not appear to affect acute substrate utilization during exercise. Thus, its contribution to obesity risk may be primarily mediated by behavioral and neuroendocrine mechanisms influencing energy intake rather than impairments in metabolic flexibility.},
	doi = {10.1139/apnm-2025-0344},
	pmid = {41429006 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.molmet.2025.102305,
	author = {Grothen JER and Martinez JM and Sidiropoulos N and Massier L and Zareifi D and Zhong J and Davidsen I and Platou JW and Mandelbaum J and Rothe P and Hvid H, Grønborg M and Madsen CT and Bruun JM, Rydén M and Mejhert N and Helge JW and Gerhart-Hines Z and Pedersen TÅ},
	title = {Single cell transcriptomics of human weight loss links adipocyte NPY1R to control of lipolysis.},
	abstract = {BACKGROUND: Combination of increased physical exercise and hypocaloric diet has long been recognized to improve cardiometabolic health and adipose tissue function, including lipid turnover. How such lifestyle interventions mediate benefits at the cellular level remains unknown. Given the critical role of subcutaneous white adipose tissue (scWAT) to systemic metabolic homeostasis, we set out to interrogate how exercise and diet lifestyle intervention impacted scWAT in individuals living with obesity, with a particular focus on lipolytic capacity and cell-specific gene profiling. METHODS: Single nuclei RNA sequencing (snRNAseq) was performed on cryopreserved scWAT biopsies originally collected before and after lifestyle intervention, involving regular exercise and hypocaloric diet in obese individuals. Findings on regulation of lipolysis in adipocytes were followed up with meta-analysis of clinical studies and pharmacological experiments in mature human adipocytes. RESULTS: snRNAseq analysis revealed intervention-induced changes in all scWAT cell-types. In adipocytes genes linked to protein and organelle turnover, branch chain amino acid catabolism, and lipolytic control were most significantly regulated. We identified a cell autonomous brake on adipocyte lipolysis via the neuropeptide Y receptor 1 (NPY1R). Expression of adipocyte NPY1R was reduced after weight loss and correlated positively with body fat percentage and body mass index. Findings were confirmed in meta-analysis across 23 studies. Finally, we found a negative correlation between NPY1R and beta-adrenergic-induced lipolysis and that NPY dose-dependently attenuated lipolysis and cAMP-signaling in primary human subcutaneous adipocytes. CONCLUSIONS: Our work suggests that decreases in adipocyte NPY1R during weight loss boost lipolytic capacity and contribute to improved systemic cardiometabolic health.},
	doi = {10.1016/j.molmet.2025.102305},
	pmid = {41412283 [Indexed for MEDLINE]},
	note = {PMC12926987}
}

@ARTICLE{10.1016/j.abb.2025.110703,
	author = {Guan C and Han R and Liu L and Liu J and Fu S and Tang X},
	title = {Exploring the multiple mechanisms of Hydroxytyrosol in treating obesity.},
	journal = {Arch Biochem Biophys},
	year = {2026},
	abstract = {BACKGROUND: The exploration of multi-mechanism therapeutics may represent a key strategy for treating obesity and metabolic dysfunction-associated steatotic liver disease. Hydroxytyrosol (HT), a phenolic compound derived from olive oil in the Mediterranean diet, exhibits potential for obesity treatment; however, its precise mechanisms remain incompletely understood. OBJECTIVE: This study aimed to elucidate the therapeutic effects of HT in obesity and to uncover its underlying regulatory mechanisms. METHODS: An obesity model was induced in C57BL/6 mice via a high-fat diet (HFD) to evaluate the in vivo effects of HT. Assessments included glucose tolerance test (GTT), insulin tolerance test (ITT) and biochemical analyses of fasting blood glucose (FBG), fasting serum insulin (FINS), uric acid (UA), blood lipid, aspartate aminotransferase (AST), and alanine aminotransferase (ALT). Hepatic, skeletal muscle, myocardial and adipose tissue (AT) morphology were examined via H&E staining. In vitro, 3T3-L1 preadipocytes were used to investigate the effects of HT on adipogenesis and thermogenic capacity. Lipid accumulation was assessed by Oil Red O and BODIPY 493/503 staining. Protein expression levels were determined via immunohistochemistry and Western blot analysis. RESULTS: HFD feeding led to increased body weight, FBG, FINS, UA, AST, ALT, and the area under the curve (AUC) for GTT and ITT. H&E staining revealed hepatic vacuolization, skeletal muscle fiber hypertrophy, and myocardial disorganization in HFD-fed mice. HT treatment significantly reduced body weight, improved glucose homeostasis, lipid metabolism, and liver function, and restored normal tissue morphology of liver, skeletal muscle, myocardium, and AT. HFD upregulated the expression of PPARγ, C/EBPβ, FABP4, STING1, and NLRP3 proteins in white AT, which were markedly attenuated by HT. HT reversed HFD-induced downregulation of PGC1α and UCP1 in brown AT. In vitro experiments confirmed that HT modulates adipogenesis and thermogenic activation in preadipocyte via the STING1/NLRP3 pathways. CONCLUSION: These findings demonstrate that HT acts as a novel anti-obesity agent by targeting the STING1/NLRP3 axis to suppress adipogenesis in adipose tissue and ameliorate obesity-related alterations in AT, liver, skeletal muscle, and myocardium. This study provides a mechanistic foundation for the potential application of HT in obesity intervention.},
	doi = {10.1016/j.abb.2025.110703},
	pmid = {41389891 [Indexed for MEDLINE]}
}

@ARTICLE{10.1002/mnfr.70352,
	author = {Almasri F and Aimaretti E and Sus N, Schéle E and Dickson SL and Landberg R and Collino M and Frank J},
	title = {Unfermented High-Fiber Rye Crispbread Increases Plasma HDL and Reduces Hepatic Lipids Compared to Refined Wheat in Rats Fed a High-Fat Diet.},
	abstract = {Fiber-rich rye foods reduced body weight in overweight or obese individuals compared to refined wheat, though the underlying mechanisms remain unclear. This study compared the effects of whole grain fermented and unfermented rye with refined wheat crispbread on body weight and lipid metabolism in rats. Exploratory outcomes included adiposity, appetite biomarkers, glucose homeostasis, colon inflammation, integrity, and permeability. Sprague Dawley rats (n = 54) were acclimatized (2 weeks) and randomized to control (n = 9) or high-fat diets (n = 45) for 16 weeks. Animals in the high-fat group were randomized to continue the high-fat (n = 9) or receive a standard diet alone (n = 9) or the standard diet with either refined wheat crispbread (n = 9), fermented rye crispbread (n = 9), or unfermented rye crispbread (n = 9) for 8 weeks. A high-fat diet did not affect final body weight, glucose homeostasis, and colon inflammation, but increased energy intake, adiposity, and leptin compared to control, and hepatic triacylglycerols compared to all other groups. Unfermented rye crispbread increased plasma HDL-cholesterol and reduced hepatic triacylglycerols and cholesterol compared to refined wheat, despite the absence of effects on obesity and glycemic control. No differences were observed between fermented and unfermented rye. Unfermented whole-grain rye crispbread may potentially exhibit favorable lipid-modulating effects.},
	doi = {10.1002/mnfr.70352},
	pmid = {41388979 [Indexed for MEDLINE]},
	note = {PMC12728384}
}

@ARTICLE{10.1111/jgh.70201,
	author = {Fan JB and Qin LQ and Ding L and Zhang L and Shao MM and Tong X and Xu JY},
	title = {Effects of Piperine on Obese and Lean Nonalcoholic Fatty Liver Disease in Mice.},
	journal = {J Gastroenterol Hepatol},
	year = {2026},
	abstract = {Nonalcoholic fatty liver disease (NAFLD) is commonly associated with overweight and obesity. But an increasing number of cases involve lean individuals, who tend to experience worse liver outcomes. In this study, we established mouse models of both obese and lean NAFLD by feeding mice a Western diet (WD) ad libitum and a WD with 30% caloric restriction (CR), respectively, to investigate the effects of piperine. After 12 weeks, hepatocyte lipid deposition and liver injury were similar in lean and obese NAFLD mice. Piperine treatment significantly reduced serum ALT levels and hepatic triglyceride (TG) content, alleviating hepatic steatosis in both groups. The mechanism of action involved the downregulation of fatty acid uptake, as evidenced by reduced expression of PPARγ and CD36, as well as the promotion of lipolysis through upregulation of hormone-sensitive lipase (HSL) and adipose triglyceride lipase (ATGL). Additionally, piperine enhanced hepatic mitochondrial β-oxidation in the obese NAFLD model by upregulating carnitine palmitoyltransferase 1A (CPT1A). In conclusion, feeding a WD with 30% CR successfully induced lean NAFLD in mice, and piperine effectively alleviated NAFLD in both lean and obese mice.},
	doi = {10.1111/jgh.70201},
	pmid = {41367157 [Indexed for MEDLINE]}
}

@ARTICLE{10.1111/dom.70371,
	author = {Hu Y and Zhao J and Xu S and Liu J and Xu J and Zhang Y and Chang J and Liu X},
	title = {Hypobaric hypoxia disrupts brown adipose thermogenic function in mice via Plin2 upregulation.},
	journal = {Diabetes Obes Metab},
	year = {2026},
	abstract = {OBJECTIVE: High-altitude environments are characterized by hypobaric hypoxia and pose a significant physiological challenge. While obesity-related hypoxia is known to impair brown adipose tissue (BAT) function by suppressing lipolysis and thermogenesis, whether hypobaric hypoxia similarly compromises BAT function remains unclear. We hypothesize that, unlike obesity-associated hypoxia, hypobaric hypoxia perturbs BAT thermogenesis via a distinct mechanism involving the upregulation of Plin2. METHODS: Mice were exposed to either normoxia or hypobaric hypoxia (simulating 6000 m, 9.2% O2) for 30 days. BAT function was assessed by analyzing lipid droplet size, lipid and triglyceride content, and expression of thermogenic protein. Thermogenic capacity was further evaluated in mice subjected to 30 days of normoxia or hypobaric hypoxia, followed by a 2-day cold exposure or 3-day treatment with the β3-adrenergic agonist CL316243. Differential proteomics and in vitro experiments were performed to explore underlying molecular mechanisms. RESULTS: After 30 days of hypobaric hypoxia, mice exhibited reduced body weight (normoxia: 26.64 ± 0.91 vs. hypoxia: 21.94 ± 0.79 g, p = 0.002), yet exhibited enlarged lipid droplets in BAT (142.7 ± 15.52 vs. 387.4 ± 31.91 μm2, p < 0.001) and increased lipid accumulation. Compared with normoxia, hypoxic mice displayed impaired thermogenic responses to both cold exposure and β3-adrenergic stimulation, as indicated by suppressed thermogenic gene expression. Mechanistically, hypobaric hypoxia elevated lactate levels and upregulated PPARγ, which subsequently enhanced Plin2 expression, ultimately leading to defective lipolysis and impaired thermogenesis. CONCLUSIONS: We identify a novel hypoxia-lactate/PPARγ-Plin2 axis that uncouples body weight loss from BAT thermogenesis under hypobaric hypoxia. This pathway represents a previously unrecognized therapeutic target for counteracting metabolic dysfunction induced by high-altitude exposure.},
	doi = {10.1111/dom.70371},
	pmid = {41366228 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.ejphar.2025.178436,
	author = {Comella F and Melini S and Opallo N and Di Napoli E and Navatti NP and Paciello O and Ferrante MC and Meli R and Mattace Raso G and Pirozzi C},
	title = {Uncovering the pleiotropic effects of oleoylethanolamide on obesity-driven chronic kidney disease in mice.},
	journal = {Eur J Pharmacol},
	year = {2026},
	abstract = {Metabolic alterations, resulting from obesity, drive chronic kidney disease (CKD) through mechanisms including lipotoxicity, inflammation, and fibrosis. Oleoylethanolamide (OEA), an endogenous compound belonging to the N-acylethanolamine family, has been widely studied for its metabolic properties. However, emerging evidence highlights its anti-inflammatory and anti-fibrotic effects. Here, we explored the effect of OEA on high-fat diet (HFD)-induced renal damage associated with obesity in mice. OEA treatment improved kidney function by restoring urine output and reducing proteinuria and albuminuria in obese mice. Moreover, OEA normalized serum creatinine and blood urea nitrogen levels, which were altered by HFD feeding, and decreased the transcription of kidney injury molecule-1 and neutrophil gelatinase-associated lipocalin, associated with renal damage. OEA also counteracted renal glucose dysmetabolism by reducing glycogen content and modulating the protein expression of glucose transporters. Furthermore, OEA exerted marked anti-inflammatory and antifibrotic effects in kidney, further confirmed by a reduction in the transcription of pro-inflammatory and pro-fibrotic markers. OEA reduced renal steatosis, improving lipid metabolism through increased peroxisome proliferator-activated receptor-α and fibroblast growth factor 21 transcription and reduced triglyceride trafficking by the downregulation of diacylglycerol O-acyltransferase 1. Finally, to highlight the direct effect of OEA in the kidney, we confirmed its protective activity against lipotoxicity and demonstrated its ability to improve mitochondrial bioenergetics in human proximal tubular epithelial cells (HK-2). These results indicate that OEA may be a promising therapeutic molecule for restraining CKD-related alterations associated with obesity and metabolic disorders.},
	doi = {10.1016/j.ejphar.2025.178436},
	pmid = {41352699 [Indexed for MEDLINE]}
}
